windowclass.script:
			function update()
				local bReadOnly = WindowManager.getReadOnlyState(getDatabaseNode());
				
				fullname.setReadOnly(bReadOnly);
				name.setReadOnly(bReadOnly);

				WindowManager.callSafeControlUpdate(self, "class", bReadOnly);
				self["class"].setComboBoxReadOnly(bReadOnly);

				type.setReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "skilltype", bReadOnly);
				self["skilltype"].setComboBoxReadOnly(bReadOnly);

				group.setReadOnly(bReadOnly);
				calc.setReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "progression", bReadOnly);
				self["progression"].setComboBoxReadOnly(bReadOnly);
				stats.setReadOnly(bReadOnly);
				armorfactor.setReadOnly(bReadOnly);
				
				WindowManager.callSafeControlUpdate(self, "core_level_bonus_group", bReadOnly);
				self["core_level_bonus_group"].setComboBoxReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "rm2_level_bonus_group", bReadOnly);
				self["rm2_level_bonus_group"].setComboBoxReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "rmfrp_level_bonus_group", bReadOnly);
				self["rmfrp_level_bonus_group"].setComboBoxReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "rmcompanion2_level_bonus_group", bReadOnly);
				self["rmcompanion2_level_bonus_group"].setComboBoxReadOnly(bReadOnly);

				description.setReadOnly(bReadOnly);
			end

combobox_columnh_skill.script:
					function onInit()
						super.onInit();

						addItems(Rules_Skills.ClassList());

						if getValue() == "" then
							setValue(Rules_Skills.GetClassName(window.fullname.getValue()));
						end
					end

					function onInit()
						super.onInit();

						addItems(Rules_Skills.TypeList());

						local sSkillType = getValue();
						if not sSkillType or sSkillType == "" then
							local nTypeID = window.type.getValue();
							setValue(Rules_Skills.GetTypeName(nTypeID));
						else
							window.type.setValue(Rules_Skills.GetTypeID(getValue()));
						end
					end
					
					function onValueChanged()
						window.type.setValue(Rules_Skills.GetTypeID(getValue()));
					end

					function onInit()
						super.onInit();

						addItems(Rules_Skills.ProgressionList());

						local sSkilProgression = getValue();
						if not sSkillProgression or sSkillProgression == "" then
							local nProgressionID = window.calc.getValue();
							setValue(Rules_Skills.GetProgressionName(nProgressionID));
						else
							window.calc.setValue(Rules_Skills.GetProgressionID(getValue()));
						end
					end
					
					function onValueChanged()
						window.calc.setValue(Rules_Skills.GetProgressionID(getValue()));
					end
